sql:
SELECT part_name
FROM parts
WHERE part_id = '0';

SELECT part_id, MIN(inventory_level) AS min_inventory_level
FROM inventories
GROUP BY part_id;

SELECT metric_name, metric_value
FROM production_metrics
WHERE task_id = '0';

SELECT task_name, setup_time, per_unit_time, AVG(setup_time) OVER () AS avg_setup_time
FROM tasks
WHERE status = 'in-progress';

SELECT COUNT(*) as production_rate_count
FROM production_metrics
WHERE metric_name = 'production rate';

SELECT task_id, AVG(production_rate) AS avg_production_rate
FROM task_parts
GROUP BY task_id;

SELECT MAX(metric_value) AS max_production_rate
FROM production_metrics
WHERE metric_name = 'production rate';

external_knowledge:
- Struggling with lead times refers to tasks that have a high average lead time compared to a standard or average; 
- Average lead time is the mean time it takes to complete tasks; 
- Below-standard production runs refer to production runs with a quality status that is not meeting the desired standards.

